You can use this cloud function to manage users.

Currently, only SELECT statements are available. If you need other SQL statements, please contact us through the official community.

Here’s sample code for testing this cloud function in a Mini Program: 

```js

// Get One
wx.cloud.callFunction({
  name: 'user-management',
  data: {
    action: 'getUser',
    data: {
      id: 'xxx'
    }
  }
}).then(res => {
  console.log('Get One: ', res)
})

// response
{
  "_id": "xxx",
  "username": "张三",
  "email": "zhangsan@example.com",
  "phone": "13900139000"
  // ...
}

// Get user list with pagination
wx.cloud.callFunction({
  name: 'user-management',
  data: {
    action: 'listUsers',
    data: {
      page: 1,
      pageSize: 10
    }
  }
}).then(res => {
  console.log('Get List: ', res)
})

// response
{
  "list": [
    {
      "_id": "xxx",
      "username": "张三",
      "email": "zhangsan@example.com",
      "phone": "13900139000"
    }
    // ... more
  ],
  "total": 100,
  "page": 1,
  "pageSize": 10
}

// Search
wx.cloud.callFunction({
  name: 'user-management',
  data: {
    action: 'searchUsers',
    data: {
      keyword: '张三'
    }
  }
}).then(res => {
  console.log('Search: ', res)
})

// response
[
  {
    "id": 1,
    "username": "张三",
    "email": "zhangsan@example.com",
    "phone": "13900139000",
  }
  // ... more
]
```
